insert into library_topics (title, source, system, summary, content, amc_exam_type, difficulty) values
(
  'Chest Pain — Acute Coronary Syndrome',
  'eTG Cardiovascular',
  'Cardiology',
  'ACS encompasses STEMI, NSTEMI and unstable angina. Rapid risk stratification and antiplatelet therapy are critical.',
  '{"overview":"Acute Coronary Syndrome (ACS) refers to a spectrum of conditions caused by sudden reduced blood flow to the heart, including STEMI, NSTEMI, and unstable angina.","key_points":["STEMI: ST elevation ≥1mm in ≥2 contiguous limb leads or ≥2mm in chest leads — activate cath lab immediately","NSTEMI: Troponin rise without ST elevation — treat with DAPT, anticoagulation, risk stratify with TIMI/GRACE score","Unstable angina: Typical symptoms, no troponin rise, ECG changes may be present","First-line: Aspirin 300mg + Ticagrelor 180mg (or Clopidogrel 300mg if Ticagrelor unavailable)","Morphine, O2 (if SpO2 <94%), Nitrates (if not hypotensive) — consider GTN sublingual","Heparin (UFH or LMWH) as anticoagulation bridge","PCI preferred over thrombolysis if available within 120 mins of first medical contact"],"amc_relevance":"Extremely high yield for both CAT 1 and CAT 2. Know the STEMI vs NSTEMI distinction, immediate management steps, and contraindications to thrombolysis.","red_flags":["Cardiogenic shock","Pulmonary oedema","Mechanical complications (VSD, MR)"],"reference":"eTG Cardiovascular — Acute Coronary Syndromes (2024)"}',
  array['CAT 1', 'CAT 2'],
  'Medium'
),
(
  'Type 2 Diabetes — Management',
  'eTG Endocrinology',
  'Endocrinology',
  'Lifestyle first, then metformin. Escalate stepwise. Manage cardiovascular risk aggressively.',
  '{"overview":"Type 2 diabetes management requires individualised HbA1c targets, stepwise pharmacotherapy, and aggressive cardiovascular risk factor modification.","key_points":["Target HbA1c: generally <53 mmol/mol (7%) — individualise based on age, comorbidities, hypoglycaemia risk","Step 1: Lifestyle — diet, exercise, weight loss (even 5-10% weight loss significantly improves glycaemic control)","Step 2: Metformin 500mg BD with food, uptitrate to 1g BD over 4 weeks (contraindicated if eGFR <30)","Step 3: Add SGLT2 inhibitor (empagliflozin/dapagliflozin) — especially if CVD or CKD","GLP-1 agonists (semaglutide) — excellent for weight loss + cardiovascular benefit","Sulfonylureas — cheap but hypoglycaemia risk, use cautiously in elderly","Annual screening: HbA1c, lipids, renal function, urine ACR, retinal exam, foot exam, BP"],"amc_relevance":"High yield for CAT 1 MCQs. Focus on metformin contraindications, SGLT2 benefits in CKD/CVD, and hypoglycaemia management.","red_flags":["DKA (Type 1 or insulin-deficient Type 2)","HHS — hyperosmolar hyperglycaemic state"],"reference":"eTG Endocrinology — Type 2 Diabetes (2024)"}',
  array['CAT 1'],
  'Medium'
),
(
  'Hypertension — Management',
  'eTG Cardiovascular',
  'Cardiology',
  'Target <130/80 in most. First-line: ACEi/ARB + CCB ± thiazide. Always assess total CV risk.',
  '{"overview":"Hypertension is defined as persistent BP ≥140/90 mmHg. Management involves lifestyle modification and stepwise pharmacotherapy based on cardiovascular risk.","key_points":["Confirm with ambulatory BP monitoring (ABPM) or home readings before diagnosing","Target: <130/80 mmHg in most patients; <140/90 in elderly or those at higher risk of falls","Step 1: Lifestyle — DASH diet, reduce sodium (<2g/day), exercise, limit alcohol, weight loss","Step 2: First-line agents — ACE inhibitor OR ARB (avoid combination), CCB, or thiazide diuretic","Preferred: ACEi/ARB in diabetes or CKD; CCB or thiazide in isolated systolic or elderly","Step 3: Combine two agents (ACEi + CCB is favoured combination)","Step 4: Add spironolactone or alpha-blocker for resistant hypertension","Hypertensive emergency (>180/120 + end-organ damage): IV labetalol or GTN infusion"],"amc_relevance":"Very high yield. Know the preferred agents per comorbidity (DM, CKD, HF, pregnancy) and the approach to resistant hypertension.","red_flags":["Hypertensive emergency","Secondary hypertension (renal artery stenosis, phaeochromocytoma, Conn''s)"],"reference":"eTG Cardiovascular — Hypertension (2024)"}',
  array['CAT 1', 'CAT 2'],
  'Easy'
),
(
  'Acute Asthma — Emergency Management',
  'eTG Respiratory',
  'Respiratory',
  'Severity assessment drives management. SABA + ipratropium + systemic steroids for moderate-severe. Early ICU referral if severe.',
  '{"overview":"Acute asthma severity is classified as mild, moderate, severe, or life-threatening. Management is driven by objective severity assessment.","key_points":["Severity: Mild (PEFR >75%), Moderate (50-75%), Severe (<50%), Life-threatening (<33% or silent chest/cyanosis/altered consciousness)","All patients: Salbutamol 2.5-5mg nebulised every 20 mins (or 4-8 puffs via spacer)","Moderate-Severe: Add ipratropium 500mcg nebulised, systemic corticosteroids (prednisolone 40-50mg oral or hydrocortisone 100mg IV)","Severe/Life-threatening: IV magnesium sulphate 2g over 20 mins, consider IV salbutamol, ICU referral","Oxygen: target SpO2 93-95% (avoid hyperoxia)","Discharge: Only if PEFR >75% sustained, oral steroids for 5 days, written asthma action plan, GP follow-up within 48h","Triggers: NSAIDS, beta-blockers, allergens — always review"],"amc_relevance":"High yield for both CAT 1 and CAT 2. Know the severity classification criteria, step-by-step management, and safe discharge criteria.","red_flags":["Silent chest","Hypercapnia on ABG","Altered consciousness","Bradycardia"],"reference":"eTG Respiratory — Asthma (2024)"}',
  array['CAT 1', 'CAT 2'],
  'Medium'
),
(
  'Sepsis — Recognition & Management',
  'Oxford Handbook of Emergency Medicine',
  'Emergency Medicine',
  'Use qSOFA to screen. Sepsis-3 definition. The Sepsis 6 bundle within 1 hour saves lives.',
  '{"overview":"Sepsis is life-threatening organ dysfunction caused by dysregulated host response to infection. Early recognition and the Sepsis 6 bundle are critical.","key_points":["qSOFA (quick screen): RR ≥22, altered mentation, SBP ≤100 — ≥2 suggests sepsis","Sepsis-3 definition: suspected infection + SOFA score increase ≥2","Septic shock: vasopressors needed to maintain MAP ≥65 + lactate >2 despite fluids","Sepsis 6 — within 1 hour: (1) Blood cultures x2, (2) IV antibiotics, (3) IV fluids 30ml/kg, (4) Lactate, (5) Urine output monitoring, (6) High-flow oxygen","Antibiotic choice: broad-spectrum empiric (piperacillin-tazobactam ± gentamicin) — narrow when cultures available","Vasopressors: noradrenaline first-line if fluid-refractory hypotension","ICU involvement early — do not delay for septic shock"],"amc_relevance":"Extremely high yield. The Sepsis 6 bundle is commonly tested. Know qSOFA criteria, septic shock definition, and antibiotic principles.","red_flags":["Lactate >4 mmol/L","MAP <65 despite fluids","Organ dysfunction (AKI, coagulopathy, altered GCS)"],"reference":"Oxford Handbook of Emergency Medicine — Sepsis (2024)"}',
  array['CAT 1', 'CAT 2'],
  'Hard'
),
(
  'Consent & Capacity — Ethics Framework',
  'AMC Ethics Framework',
  'Ethics & Communication',
  'Valid consent requires capacity, disclosure, voluntariness. Assess capacity with the four-component test.',
  '{"overview":"Informed consent is a cornerstone of medical ethics. Every competent adult has the right to refuse or accept treatment. Capacity must be assessed, not assumed.","key_points":["Four components of capacity: (1) Understand the information, (2) Retain it, (3) Weigh it up, (4) Communicate a decision","Capacity is decision-specific and time-specific — reassess if condition changes","Valid consent: Must be voluntary, informed, and given by a person with capacity","If no capacity: Identify substitute decision maker (SDM) — usually next of kin in order of priority per state legislation","Advance care directives must be respected if valid and applicable","Children: Gillick competence — assess if child understands the nature and consequences of treatment","Emergency exception: If life-threatening and no time to assess, treat in best interests"],"amc_relevance":"Core CAT 2 communication domain. Examiners look for systematic capacity assessment, non-judgmental approach, and knowledge of SDM hierarchy.","red_flags":["Coercion from family","Fluctuating consciousness affecting capacity","Cultural/language barriers to true informed consent"],"reference":"AMC Good Medical Practice — Consent (2023)"}',
  array['CAT 2'],
  'Medium'
)
on conflict do nothing;

